// Single source of truth for OAuth entry points — used on both Login and
// Register so the two pages stay symmetric (Antigravity flagged register
// missing the social options login had).
const PROVIDERS = [
  { label: 'Google', href: `${API_BASE_URL}/auth/google`, Icon: GoogleIcon },
  { label: 'GitHub', href: `${API_BASE_URL}/login/github`, Icon: GitHubIcon },
  { label: 'LinkedIn', href: `${API_BASE_URL}/login/linkedin`, Icon: LinkedInIcon },
]

export default function SocialAuthButtons({ verb = 'Continue' }) {
  return (
    <div className="space-y-2.5">
      {/* eslint-disable-next-line no-unused-vars -- Icon is used as <Icon /> JSX; eslint-plugin-react missing from config (false positive, see CurationDiscipline.jsx) */}
      {PROVIDERS.map(({ label, href, Icon }) => (
        <a
          key={label}
          href={href}
          className="inline-flex w-full items-center justify-center gap-2 rounded-lg border border-line-strong bg-bg-elev px-4 py-2.5 text-sm font-medium text-ink-2 transition hover:bg-bg-sunk hover:border-accent"
        >
          <Icon />
          {verb} with {label}
        </a>
      ))}
    </div>
  )
}
